def parse_query(qs: str) -> dict:
    def url_decode(s: str) -> str:
        result = []
        i = 0
        while i < len(s):
            c = s[i]
            if c == '+':
                result.append(' ')
                i += 1
            elif c == '%':
                if i + 2 >= len(s):
                    raise ValueError(f"Malformed percent escape near index {i}: {s[i:]}")
                hex_str = s[i+1:i+3]
                if not all(ch in '0123456789ABCDEFabcdef' for ch in hex_str):
                    raise ValueError(f"Malformed percent escape: %{hex_str}")
                result.append(chr(int(hex_str, 16)))
                i += 3
            else:
                result.append(c)
                i += 1
        return ''.join(result)

    def parse_key_path(raw_key: str) -> list:
        """Parse bracket notation into path segments. Operates on raw (undecoded) key."""
        parts = []
        # Find first '[' or ']'
        j = 0
        while j < len(raw_key) and raw_key[j] not in ('[]'):
            j += 1
        if j < len(raw_key) and raw_key[j] == ']':
            raise ValueError(f"Unbalanced ']' in key: {raw_key!r}")
        # Decode first segment
        parts.append(url_decode(raw_key[:j]))
        rest = raw_key[j:]
        while rest:
            if rest[0] != '[':
                raise ValueError(f"Expected '[' in key: {raw_key!r}")
            close = rest.find(']')
            if close == -1:
                raise ValueError(f"Unclosed '[' in key: {raw_key!r}")
            inner = rest[1:close]
            if '[' in inner or ']' in inner:
                raise ValueError(f"Nested brackets in key: {raw_key!r}")
            parts.append(url_decode(inner))
            rest = rest[close+1:]
        return parts

    def set_nested(root: dict, path: list, value: str) -> None:
        if not path:
            raise ValueError("Empty path")
        last = path[-1]
        if last == '':
            # List-append mode: path ends with ''
            if len(path) < 2:
                raise ValueError("No list key found in path")
            nav_path = path[:-2]
            list_key = path[-2]
            if list_key == '':
                raise ValueError("Empty bracket in middle of path")
            current = root
            for key in nav_path:
                if key == '':
                    raise ValueError("Empty bracket in middle of path")
                if not isinstance(current.get(key), dict):
                    current[key] = {}
                current = current[key]
            if not isinstance(current.get(list_key), list):
                current[list_key] = []
            current[list_key].append(value)
        else:
            # Dict-set mode
            nav_path = path[:-1]
            set_key = path[-1]
            current = root
            for key in nav_path:
                if key == '':
                    raise ValueError("Empty bracket in middle of path")
                if not isinstance(current.get(key), dict):
                    current[key] = {}
                current = current[key]
            current[set_key] = value

    result: dict = {}
    if not qs:
        return result

    for pair in qs.split('&'):
        if not pair:
            continue
        if '=' in pair:
            eq = pair.index('=')
            raw_key = pair[:eq]
            raw_val = pair[eq+1:]
        else:
            raw_key = pair
            raw_val = ''

        value = url_decode(raw_val)
        path = parse_key_path(raw_key)
        set_nested(result, path, value)

    return result

